const getProvider = () => {
const rootData = inject('syDialogState');

state.syDialogState = rootData;
};
const initPage = () => {
const stateArr = [{
  "color": "#00FFFF",
  "bgColor": "rgba(45, 149, 90, 0.3)"
},
{
  "color": "#FFF200",
  "bgColor": "rgba(255, 242, 0, 0.2)"
}]

console.log('state.syDialogState 信访投诉', state.syDialogState);

watch(
  () => state.syDialogState,
  (val) => {
    const { isShowCard, punish, over, trend, emission, pollute, xfts } = val
    if (isShowCard) {
      state.isShowCard = { ...isShowCard };
    }
    if (punish) {
      state.punish = { ...punish };
    }
    if (xfts) {
      state.xfts = { ...xfts };
    }
    if (over) {
      state.over = { ...over };
    }
    if (trend) {
      state.trend = trend;
    }
    if (emission) {
      state.emission.list = emission.list
      state.emission.header[1].label = `${emission.year}年排放量（t/a)`
    }
    if (pollute) {
      state.pollute = pollute
        .filter(i => i.label)
        .map(i => ({
          state: i.label,
          stateColor: stateArr[Number(!i.normal)].color,
          stateBgColor: stateArr[Number(!i.normal)].bgColor
        }));
    }
  },
  {
    immediate: true,
    deep: true
  }
)
};let apiRegistry = {}; 

